import logger from '../utils/logger.js';

/**
 * AgentOrchestrator - Orchestrates the agentic workflow and tool execution
 * 
 * Responsibilities:
 * - Manage the agent execution loop
 * - Send messages to AI with tool definitions
 * - Parse tool calls from AI responses
 * - Execute tools through ToolRegistry
 * - Send tool results back to AI
 * - Continue loop until AI provides final response
 * - Handle multi-step reasoning and tool chaining
 */
class AgentOrchestrator {
  /**
   * Create a new AgentOrchestrator
   * @param {MistralClient} mistralClient - Mistral AI client instance
   * @param {ToolRegistry} toolRegistry - Tool registry instance
   * @param {Object} approvalManager - Approval manager instance (optional)
   * @param {Object} options - Configuration options
   */
  constructor(mistralClient, toolRegistry, approvalManager = null, options = {}) {
    if (!mistralClient) {
      throw new Error('MistralClient is required');
    }

    if (!toolRegistry) {
      throw new Error('ToolRegistry is required');
    }

    this.mistralClient = mistralClient;
    this.toolRegistry = toolRegistry;
    this.approvalManager = approvalManager;

    // Configuration options
    this.options = {
      maxToolCalls: options.maxToolCalls || 10,
      maxIterations: options.maxIterations || 20,
      streamResponses: options.streamResponses !== false, // Default to true
      displayToolCalls: options.displayToolCalls !== false, // Default to true
      ...options
    };

    // State tracking
    this.isProcessing = false;
    this.currentIteration = 0;
    this.toolCallHistory = [];
  }

  /**
   * Process a user message through the agentic workflow
   * @param {string} userMessage - The user's message
   * @param {ContextManager} contextManager - Context manager with conversation history
   * @param {Object} options - Processing options
   * @returns {Promise<Object>} Final response from the agent
   */
  async processMessage(userMessage, contextManager, options = {}) {
    if (!userMessage || typeof userMessage !== 'string') {
      throw new Error('User message must be a non-empty string');
    }

    if (!contextManager) {
      throw new Error('ContextManager is required');
    }

    if (this.isProcessing) {
      throw new Error('Agent is already processing a message');
    }

    this.isProcessing = true;
    this.currentIteration = 0;
    this.toolCallHistory = [];

    try {
      // Add user message to context
      contextManager.addMessage('user', userMessage);

      // Execute the agent loop
      const result = await this.executeAgentLoop(contextManager, options);

      return result;
    } catch (error) {
      logger.error('Agent message processing failed', { error: error.message });
      throw error;
    } finally {
      this.isProcessing = false;
    }
  }

  /**
   * Execute the main agent loop with multi-step reasoning
   * @param {ContextManager} contextManager - Context manager instance
   * @param {Object} options - Execution options
   * @returns {Promise<Object>} Final response
   */
  async executeAgentLoop(contextManager, options = {}) {
    const {
      onToolCall = null,
      onToolResult = null,
      onResponse = null
    } = options;

    // Register tools with the AI client
    const toolDefinitions = this.toolRegistry.getToolDefinitions();
    this.mistralClient.registerTools(toolDefinitions);

    while (this.currentIteration < this.options.maxIterations) {
      this.currentIteration++;

      try {
        // Get current messages for AI
        const messages = contextManager.getMessages().map(msg => ({
          role: msg.role,
          content: msg.content
        }));

        // Send message with tools to AI
        const response = await this.mistralClient.sendWithTools(messages, toolDefinitions);

        // Check if AI wants to use tools
        if (response.toolCalls && response.toolCalls.length > 0) {
          // Process each tool call
          const toolResults = [];

          for (const toolCall of response.toolCalls) {
            const toolResult = await this.handleToolCall(toolCall, onToolCall, onToolResult);
            toolResults.push(toolResult);
          }

          // Add tool results to context as assistant message
          const toolResultsMessage = this._formatToolResultsMessage(response.toolCalls, toolResults);
          contextManager.addMessage('assistant', toolResultsMessage);

          // Continue the loop to let AI process tool results
          continue;
        }

        // No tool calls - AI provided final response
        if (response.content) {
          logger.info('AI provided final response');

          // Add AI response to context
          contextManager.addMessage('assistant', response.content);

          // Call response callback if provided
          if (onResponse) {
            onResponse(response.content, response);
          }

          return {
            content: response.content,
            role: 'assistant',
            finishReason: response.finishReason,
            iterations: this.currentIteration,
            toolCallsUsed: this.toolCallHistory.length,
            usage: response.usage
          };
        }

        // No content and no tool calls - unexpected response
        logger.warn('AI response had no content or tool calls', { response });
        break;

      } catch (error) {
        // Add error message to context so AI can potentially recover
        const errorMessage = `Tool execution error: ${error.message}`;
        contextManager.addMessage('system', errorMessage);

        // Continue loop to let AI try to recover
        continue;
      }
    }

    // If we exit the loop without a final response
    const errorMessage = `Agent loop exceeded maximum iterations (${this.options.maxIterations})`;
    logger.error(errorMessage);

    return {
      content: errorMessage,
      role: 'assistant',
      finishReason: 'max_iterations',
      iterations: this.currentIteration,
      toolCallsUsed: this.toolCallHistory.length,
      error: true
    };
  }

  /**
   * Handle a single tool call from the AI
   * @param {Object} toolCall - Tool call object from AI response
   * @param {Function} onToolCall - Callback for tool call events
   * @param {Function} onToolResult - Callback for tool result events
   * @returns {Promise<Object>} Tool execution result
   */
  async handleToolCall(toolCall, onToolCall = null, onToolResult = null) {
    if (!toolCall || !toolCall.function) {
      throw new Error('Invalid tool call format');
    }

    const { name: toolName, arguments: toolArgs } = toolCall.function;
    const toolCallId = toolCall.id || `call_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    // Parse arguments if they're a string
    let parsedArgs;
    try {
      parsedArgs = typeof toolArgs === 'string' ? JSON.parse(toolArgs) : toolArgs;
    } catch (error) {
      const errorMsg = `Failed to parse tool arguments: ${error.message}`;
      logger.error(errorMsg, { toolArgs });

      const result = {
        toolCallId,
        toolName,
        arguments: toolArgs,
        success: false,
        error: errorMsg,
        timestamp: new Date()
      };

      // Add to history even for parsing errors
      this.toolCallHistory.push(result);

      return result;
    }

    // Call tool call callback if provided
    if (onToolCall) {
      try {
        onToolCall(toolName, parsedArgs, toolCallId);
      } catch (error) {
        logger.warn('Tool call callback failed', { error: error.message });
      }
    }

    // Check if tool requires approval
    if (this.approvalManager) {
      try {
        const approved = await this.approvalManager.requestApproval(toolName, parsedArgs);
        if (!approved) {
          const result = {
            toolCallId,
            toolName,
            success: false,
            error: 'Tool execution denied by user'
          };

          this.toolCallHistory.push(result);
          return result;
        }
      } catch (error) {
        logger.error('Approval check failed', { error: error.message });
        const result = {
          toolCallId,
          toolName,
          success: false,
          error: `Approval check failed: ${error.message}`
        };

        this.toolCallHistory.push(result);
        return result;
      }
    }

    // Execute the tool
    try {
      const executionResult = await this.toolRegistry.executeTool(toolName, parsedArgs);

      const result = {
        toolCallId,
        toolName,
        arguments: parsedArgs,
        success: executionResult.success,
        result: executionResult.result,
        error: executionResult.error,
        timestamp: new Date()
      };

      // Add to history
      this.toolCallHistory.push(result);

      // Call result callback if provided
      if (onToolResult) {
        try {
          onToolResult(result);
        } catch (error) {
          logger.warn('Tool result callback failed', { error: error.message });
        }
      }

      logger.info(`Tool call completed: ${toolName}`, {
        toolCallId,
        success: result.success
      });

      return result;

    } catch (error) {
      const result = {
        toolCallId,
        toolName,
        arguments: parsedArgs,
        success: false,
        error: error.message,
        timestamp: new Date()
      };

      this.toolCallHistory.push(result);

      logger.error(`Tool call failed: ${toolName}`, {
        toolCallId,
        error: error.message
      });

      return result;
    }
  }

  /**
   * Determine if the agent should continue processing
   * @param {Object} response - AI response
   * @returns {boolean} True if should continue
   */
  shouldContinue(response) {
    // Continue if there are tool calls to process
    if (response.toolCalls && response.toolCalls.length > 0) {
      return true;
    }

    // Continue if no final content provided
    if (!response.content) {
      return true;
    }

    // Stop if we have final content
    return false;
  }

  /**
   * Get current agent state
   * @returns {Object} Current state
   */
  getState() {
    return {
      isProcessing: this.isProcessing,
      currentIteration: this.currentIteration,
      toolCallHistory: [...this.toolCallHistory],
      maxIterations: this.options.maxIterations,
      maxToolCalls: this.options.maxToolCalls
    };
  }

  /**
   * Reset agent state
   */
  reset() {
    this.isProcessing = false;
    this.currentIteration = 0;
    this.toolCallHistory = [];
    logger.debug('Agent state reset');
  }

  /**
   * Get tool call statistics
   * @returns {Object} Statistics about tool usage
   */
  getToolCallStats() {
    const stats = {
      totalCalls: this.toolCallHistory.length,
      successfulCalls: 0,
      failedCalls: 0,
      toolUsage: {}
    };

    this.toolCallHistory.forEach(call => {
      if (call.success) {
        stats.successfulCalls++;
      } else {
        stats.failedCalls++;
      }

      if (!stats.toolUsage[call.toolName]) {
        stats.toolUsage[call.toolName] = { count: 0, successes: 0, failures: 0 };
      }

      stats.toolUsage[call.toolName].count++;
      if (call.success) {
        stats.toolUsage[call.toolName].successes++;
      } else {
        stats.toolUsage[call.toolName].failures++;
      }
    });

    return stats;
  }

  /**
   * Format tool results into a message for the AI
   * @private
   * @param {Array} toolCalls - Original tool calls
   * @param {Array} toolResults - Tool execution results
   * @returns {string} Formatted message
   */
  _formatToolResultsMessage(toolCalls, toolResults) {
    const results = toolResults.map((result, index) => {
      const toolCall = toolCalls[index];

      if (result.success) {
        return `Tool "${result.toolName}" executed successfully. Result: ${JSON.stringify(result.result)}`;
      } else {
        return `Tool "${result.toolName}" failed with error: ${result.error}`;
      }
    });

    return `Tool execution results:\n${results.join('\n')}`;
  }
}

export default AgentOrchestrator;